$$, $$0dc9e5a9f2d0900cf43454923b9e774fabd5310b1b62653b6cd3d56eb64799e6$$, $${"A": "eef2e98e72f7ee7e25fd8699ce8f4e486ec48483b52e1f8d17d044529921b6d3", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "4f46c4c57847c4d3f447325e8d0f07f5717190e4ea33430eb69babd27b9707cd"}$$::jsonb, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$, 259, $$2026-05-07T23:10:44.305456+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0203801A$$, 2027, $$The Avenger is a lightweight, ground-to-air missile and gun weapon system mounted on a High Mobility Multi-Purpose Wheeled Vehicle (HMMWV). It is designed to
protect against unmanned aircraft systems (UAS), cruise missiles, and fixed- and rotary-wing threats. The Avenger provides day/night and adverse weather operational
capabilities, shoot-on-the-move functionality, rapid target engagement, and remote firing capability. It is highly mobile, capable of being air-dropped, helicopter-lifted, and
air-transportable. The system employs up to eight Stinger missiles to counter aerial threats and is equipped with an M3P .50 Caliber Machine Gun for close-in ground
and air defense. An Identification Friend or Foe (IFF) system is integrated to aid in identifying friendly aircraft, minimizing the risk of fratricide. The Avenger fleet consists
of 421 systems, including 169 systems equipped with a digital Slew-to-Cue (STC) capability, which enhances target detection and engagement speed.

 The Avenger Modification - Service Life Extension Program (MOD-SLEP) consists of Project 038: Avenger Production Improvement Program (PIP) and Program
 Element CE8710: Avenger MODS. The ongoing MOD-SLEP addresses the obsolescence of Avenger components to ensure Avenger maintains operational capability
 through the end of its economic useful life. Key MOD-SLEP components are the Targeting Console (TC), the M3P, the Avenger Fire Control Computer (AFCC), the
 Mode 5 IFF, the Vehicle Internal Communications (VIC-5), and the Assured Positioning Navigation and Timing (A-PNT) capability. The AFCC and TC are fielded to the
 STC Avengers. All other components are fielded to the entire Avenger fleet.

 The FY 2027 funding of $2.054 million is allocated to support ongoing system testing requirements and implement system improvements to address evolving threats.$$, $$The Avenger is a lightweight, ground-to-air missile and gun weapon system mounted on a High Mobility Multi-Purpose Wheeled Vehicle (HMMWV). It is designed to
protect against unmanned aircraft systems (UAS), cruise missiles, and fixed- and rotary-wing threats. The Avenger provides day/night and adverse weather operational
capabilities, shoot-on-the-move functionality, rapid target engagement, and remote firing capability. It is highly mobile, capable of being air-dropped, helicopter-lifted, and
air-transportable. The system employs up to eight Stinger missiles to counter aerial threats and is equipped with an M3P .50 Caliber Machine Gun for close-in ground
and air defense. An Identification Friend or Foe (IFF) system is integrated to aid in identifying friendly aircraft, minimizing the risk of fratricide. The Avenger fleet consists
of 421 systems, including 169 systems equipped with a digital Slew-to-Cue (STC) capability, which enhances target detection and engagement speed.

 The Avenger Modification - Service Life Extension Program (MOD-SLEP) consists of Project 038: Avenger Production Improvement Program (PIP) and Program
 Element CE8710: Avenger MODS. The ongoing MOD-SLEP addresses the obsolescence of Avenger components to ensure Avenger maintains operational capability
 through the end of its economic useful life. Key MOD-SLEP components are the Targeting Console (TC), the M3P, the Avenger Fire Control Computer (AFCC), the
 Mode 5 IFF, the Vehicle Internal Communications (VIC-5), and the Assured Positioning Navigation and Timing (A-PNT) capability. The AFCC and TC are fielded to the
 STC Avengers. All other components are fielded to the entire Avenger fleet.

 The FY 2027 funding of $2.054 million is allocated to support ongoing system testing requirements and implement system improvements to address evolving threats.

B. Accomplishments/Planned Programs ($ in Millions)                                                                                         FY 2025          FY 2026        FY 2027
Title: Avenger MOD-SLEP                                                                                                                         1.456            1.338          2.054
Description: The Avenger MOD-SLEP consists of development activities for platform integration, software upgrades, and
capability enhancements. Develops and executes test requirements and conducts limited contractor and government testing.
Performs technical assessments, concept studies, cost reduction, risk reduction and development documentation.

FY 2026 Plans:
FY 2026 funding continues to support system testing requirement and addresses evolving threats and obsolescence mitigation,
which allows for product improvement of repair parts that are no longer available.
FY 2027 Plans:
FY 2027 funding continues obsolescence mitigation through product improvements, which allows for the integration, testing and
qualification of replacement parts required for system improvements to address evolving threats.
